// Source: https://github.com/SlimKQL/Hunting-Queries-Detection-Rules
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

MicrosoftGraphActivityLogs
| where TimeGenerated > ago(1h)
| distinct IPAddress
| join ThreatIntelligenceIndicator on $left.IPAddress == $right.NetworkIP

//Microsoft have released a new premium user risk detection in Identity Protection called Suspicious API Traffic. This detection is reported when Identity Protection detects anomalous Graph traffic by a user. Suspicious API traffic might suggest that a user is compromised and conducting reconnaissance in their environment. 

SigninLogs
| where RiskEventTypes contains "suspiciousAPITraffic"

// MITRE ATT&CK Mapping

// Based on the operations and objectives of the KQL code, the following MITRE ATT&CK techniques are relevant:

// T1071.001 - Application Layer Protocol: Web Protocols: The use of Microsoft Graph API can be associated with web protocols.
// T1071.003 - Application Layer Protocol: Mail Protocols: If the Graph API is used for email-related activities.
// T1595.002 - Active Scanning: Vulnerability Scanning: If the IP addresses are involved in scanning activities.
// T1078 - Valid Accounts: Suspicious API traffic might indicate the use of compromised accounts.
// T1587.001 - Develop Capabilities: Malware: If the suspicious traffic is related to malware activities.
// T1589.002 - Gather Victim Network Information: DNS: If the suspicious traffic involves DNS queries.

// Source: https://github.com/ge0mant1s/soacframe-community
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

union OfficeActivity, SalesforceAuditLogs, GWorkspaceActivity
| where Operation in ("FileDownloaded", "BulkExport", "DownloadContent")
| summarize EventCount = count() by UserEmail, bin(TimeGenerated, 30m), ClientIP
| where EventCount > 50
| project TimeGenerated, UserEmail, EventCount, ClientIP

// Source: https://github.com/quintindk/fabric-shield
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

FabricPolicyCompliance_CL
| where TimeGenerated > ago(24h)
| where Status == "NonCompliant"
| summarize ViolationCount = count() by Severity
| order by case(
    Severity == "Critical", 0,
    Severity == "High", 1,
    Severity == "Medium", 2,
    Severity == "Low", 3,
    4)


// ----------------------------------------------------------------------------
// 2. Compliance Trend Over Time
// Daily violation count over the last 30 days, broken down by severity.
// Use with a Sentinel workbook time-chart visualization.
// ----------------------------------------------------------------------------
FabricPolicyCompliance_CL
| where TimeGenerated > ago(30d)
| where Status == "NonCompliant"
| summarize ViolationCount = count() by bin(TimeGenerated, 1d), Severity
| order by TimeGenerated asc


// ----------------------------------------------------------------------------
// 3. Most Violated Rules
// Top 10 policy rules by violation count in the last 7 days.
// Helps prioritize remediation efforts.
// ----------------------------------------------------------------------------
FabricPolicyCompliance_CL
| where TimeGenerated > ago(7d)
| where Status == "NonCompliant"
| summarize ViolationCount = count() by RuleName, Severity
| top 10 by ViolationCount desc


// ----------------------------------------------------------------------------
// 4. Workspace Compliance Status
// Per-workspace summary showing the number of compliant vs non-compliant
// policy evaluations. Provides a quick view of which workspaces need attention.
// ----------------------------------------------------------------------------
FabricPolicyCompliance_CL
| where TimeGenerated > ago(24h)
| summarize
    CompliantCount   = countif(Status == "Compliant"),
    NonCompliantCount = countif(Status == "NonCompliant")
    by WorkspaceName
| extend TotalEvaluated = CompliantCount + NonCompliantCount
| extend CompliancePercent = round(100.0 * CompliantCount / TotalEvaluated, 1)
| order by NonCompliantCount desc


// ----------------------------------------------------------------------------
// 5. Critical Violations Detail
// Full detail of all Critical-severity violations in the last 24 hours.
// Use for incident triage and immediate remediation.
// ----------------------------------------------------------------------------
FabricPolicyCompliance_CL
| where TimeGenerated > ago(24h)
| where Status == "NonCompliant"
| where Severity == "Critical"
| project
    TimeGenerated,
    WorkspaceName,
    ResourceName,
    ResourceType,
    RuleName,
    Severity,
    Details = Description
| order by TimeGenerated desc


// ----------------------------------------------------------------------------
// 6. Compliance Score
// Overall compliance percentage — compliant rules as a share of total
// evaluations in the last 24 hours.
// ----------------------------------------------------------------------------
FabricPolicyCompliance_CL
| where TimeGenerated > ago(24h)
| summarize
    TotalEvaluated = count(),
    CompliantCount  = countif(Status == "Compliant")
| extend ComplianceScore = round(100.0 * CompliantCount / TotalEvaluated, 1)
| project TotalEvaluated, CompliantCount, NonCompliantCount = TotalEvaluated - CompliantCount, ComplianceScore


// ----------------------------------------------------------------------------
// 7. Tenant Settings Drift History
// All changes to Fabric tenant settings over the last 30 days from the
// OfficeActivity audit log. Useful for tracking configuration drift.
// ----------------------------------------------------------------------------
OfficeActivity
| where TimeGenerated > ago(30d)
| where OfficeWorkload == "PowerBI"
| where Operation == "UpdateFabricTenantSetting"
| extend SettingName = tostring(ItemName)
| extend ChangedBy = UserId
| project TimeGenerated, SettingName, ChangedBy, ClientIP
| order by TimeGenerated desc

// Source: https://github.com/EmreOzanMemis/AzureSentinel
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let timerange=14d;
IdentityInfo
| where TimeGenerated > ago(21d)
| summarize arg_max(TimeGenerated, *) by AccountUPN
| where AssignedRoles has_any ("Global Administrator", "Exchange Administrator", "Teams Administrator", "SharePoint Administrator")
| project UserId=AccountUPN
| join kind=inner (
    OfficeActivity
    | where TimeGenerated > ago(timerange)
    )
    on UserId
| summarize AdminActivities=make_list(Operation)by UserId, startofday(TimeGenerated)

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let StartDate = ago(30d);
let usersToMonitor = dynamic(['user1@contoso.com', 'user2@contoso.com', 'user3@contoso.com']);
let OperationFilter = "FileSyncUploadedFull";
OfficeActivity
| where UserId in~ (usersToMonitor)
| where Operation == OperationFilter
| where TimeGenerated > StartDate
| make-series count(Operation) default=0 on TimeGenerated from StartDate to now() step 1d by UserId 
//| extend series_fir(count_Operation, dynamic([1,1,1,1]), true, true)
| render timechart

// Source: https://github.com/xpinux/Project-SABER
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

OfficeActivity | where Operation == "MailboxLogin" | where UserAgent contains "PowerShell" or UserAgent contains "WinRm" or UserAgent contains "RemotePowerShell" or UserAgent contains "python"

// Source: https://github.com/MorganCPatz/KQL-Queries
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let UserMailbox = <User>;
let TimeDelivered = <Time Delivered>;
let MailAccessedTimeframe = <Time Mailbox Accessed>;
let EmailActivity = EmailEvents
    | where TimeGenerated > ago (TimeDelivered)
    | where RecipientEmailAddress contains UserMailbox
    | extend EmailDelivered = TimeGenerated
    | project EmailDelivered, InternetMessageId, SenderFromAddress, Subject;
let newOfficeActivity = OfficeActivity
    | where TimeGenerated > ago (MailAccessedTimeframe)
    | where Operation == "MailItemsAccessed"
    | where MailboxOwnerUPN == UserMailbox
    | mv-expand todynamic(Folders)
    | extend InternetMessageId = tostring(Folders.FolderItems.[0].InternetMessageId)
    | extend TimeAccessed = TimeGenerated
    | project InternetMessageId, UserId, TimeAccessed, Operation
    | join kind=inner(EmailActivity
    ) on InternetMessageId;
newOfficeActivity
    | summarize arg_max(TimeAccessed, *) by Subject
    | project TimeAccessed, UserId, Operation, SenderFromAddress, Subject, EmailDelivered

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let _SampleSize = 50000;
let _analyzeSecurityEvent = SecurityEvent | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "SecurityEvent";
let _analyzeSigninLogs = SigninLogs | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "SigninLogs";
let _analyzeAADNonInteractive = AADNonInteractiveUserSignInLogs | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "AADNonInteractiveUserSignInLogs";
let _analyzeCSL = CommonSecurityLog | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "CommonSecurityLog";
let _analyzeSyslog = Syslog | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "Syslog";
let _analyzeAuditLogs = AuditLogs | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "AuditLogs";
let _analyzeAzureActivity = AzureActivity | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "AzureActivity";
let _analyzeOfficeActivity = OfficeActivity | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "OfficeActivity";
let _analyzeHeartbeat = Heartbeat | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "Heartbeat";
let _analyzeEvent = Event | where TimeGenerated > ago(1d) | take _SampleSize | evaluate narrow() | where isnotempty(tostring(Value)) | summarize AvgLenBytes = round(avg(toreal(strlen(tostring(Value)))), 0), MaxLenBytes = max(strlen(tostring(Value))) by Column | where AvgLenBytes > 0 | extend TableName = "Event";
let _allColumns = union
    _analyzeSecurityEvent, _analyzeSigninLogs, _analyzeAADNonInteractive,
    _analyzeCSL, _analyzeSyslog, _analyzeAuditLogs,
    _analyzeAzureActivity, _analyzeOfficeActivity, _analyzeHeartbeat, _analyzeEvent;
_allColumns
| join kind=inner (
    _allColumns | summarize TotalAvgLen = sum(AvgLenBytes) by TableName
) on TableName
| extend PctOfRowSize = round(AvgLenBytes / toreal(TotalAvgLen) * 100, 1)
| where PctOfRowSize > 30
| extend Recommendation = case(
    PctOfRowSize > 50, "CRITICAL: >50% of row size - Use project-away in DCR transform",
    "Medium: >30% of row size - Study to use project-away in DCR transform"
)
| project TableName, Column, AvgLenBytes, MaxLenBytes, PctOfRowSize, Recommendation
| order by TableName asc, PctOfRowSize desc

// Source: https://github.com/reversinglabs/reversinglabs-siem-rules
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let c2ips = external_data(c2ip: string) [h"https://raw.githubusercontent.com/reversinglabs/reversinglabs-siem-rules/master/Malware/NetsupportRAT/20231016/KQL/netsupportrat-20231016-c2ips.txt"];
let c2domains = external_data(c2domain: string) [h"https://raw.githubusercontent.com/reversinglabs/reversinglabs-siem-rules/master/Malware/NetsupportRAT/20231016/KQL/netsupportrat-20231016-c2domains.txt"];
let NetSupportUserAgent = "NetSupport Manager";
CommonSecurityLog
| where DestinationIP in (c2ips)
  or DestinationHostName in (c2domains)
  or RequestClientApplication contains NetSupportUserAgent
| union 
(DeviceNetworkEvents
| where RemoteIP in (c2ips)
),
(SysmonParser
| where (EventID == 3 and DestinationIp in (c2ips)))

// Source: https://github.com/xpinux/Project-SABER
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

CommonSecurityLog
| where DeviceProduct == "SmartConsole" or DeviceProduct == "SmartDashboard"
| parse-kv AdditionalExtensions as (loguid:string,origin:string,originsicname:int,rules:string,cn:string,o:string,sequencenum:string,version:string,administrator:string,additional_info:string,audit_status:string,objectname:string,objecttype:string,Policy:string,machine:string,operation:string,product:string,subject:string,advanced_changes:string,fieldchanges:string,Name:string,session_name:string) with (pair_delimiter=";",kv_delimiter="=")
| project TimeGenerated,DeviceVendor,Computer,DeviceProduct,DeviceEventClassID,LogSeverity,session_name,SourceIP,loguid,origin,sequencenum,version,administrator,additional_info,audit_status,objectname,objecttype,machine,operation,product,subject,advanced_changes,fieldchanges,Name,AdditionalExtensions,CollectorHostName,Type

// Source: https://github.com/robert-iw3/rnd_proto
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let lookback = 30m;
let error_threshold = 50; // An attacker needs to send many messages. Tune based on environment specifics.

// This rule assumes logs from an OPC UA-aware source (e.g., Zeek, specific vendor logs) are available.
// The table and field names may need to be adjusted for your environment.
union isfuzzy=true OpcUa*, Zeek*, CommonSecurityLog, DeviceNetworkEvents
| where TimeGenerated > ago(lookback)
// Filter for events that indicate an OPC UA error. This is the most critical part for customization.
| where (EventData has "error" or Message has "error" or EventResult =~ "Failure")
    and (
        // Look for generic OPC UA error indicators
        EventData has_any ("Bad", "fail", "incorrect") or
        Message has_any ("Bad", "fail", "incorrect") or
        // Look for specific strings from research on padding oracles in OPC UA
        Message has "block incorrect" or
        Message has "BadUnexpectedError" or
        Message has "Bad_InternalError"
    )
// FP Tuning: Exclude known misconfigured clients or legitimate testing activities.
// For example: | where SrcIp !in ('10.1.1.1', '192.168.5.20')
| summarize
    StartTime = min(TimeGenerated),
    EndTime = max(TimeGenerated),
    ErrorCount = count(),
    // Counting distinct error messages can be a stronger signal of probing for an error-based oracle.
    // Adjust 'Message' to the field containing the detailed error string in your logs.
    DistinctErrorMessages = dcountif(Message, isnotempty(Message))
    by SrcIp, DstIp, DstHostname, bin(TimeGenerated, 5m)
| where ErrorCount > error_threshold
| extend
    timestamp = StartTime,
    HostName = DstHostname,
    IPAddress = DstIp
| project
    timestamp,
    StartTime,
    EndTime,
    IPAddress,
    HostName,
    SrcIp,
    ErrorCount,
    DistinctErrorMessages,
    Description = "A high volume of OPC UA errors was detected from a single source, possibly indicating a padding oracle attack."

// Source: https://github.com/hchiphong/KQL
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

SentinelAudit
| where OperationName in('Microsoft.SecurityInsights/alertRules/Delete','Microsoft.SecurityInsights/alertRules/Write')
| where ExtendedProperties.UpdatedResourceState == 'null'
    or  (ExtendedProperties.OriginalResourceState != 'null'
        and parse_json(tostring(ExtendedProperties.UpdatedResourceState)).properties.enabled == false 
    )

// attacker can bypass by just add simple kql to whitelist. so we audit rule logic change
// Query Logic change
SentinelAudit
| where OperationName == 'Microsoft.SecurityInsights/alertRules/Write'
| where ExtendedProperties.OriginalResourceState != 'null' // Not newly create
| extend OldLogic = tostring(parse_json(tostring(ExtendedProperties.OriginalResourceState)).properties.query)
        ,NewLogic = tostring(parse_json(tostring(ExtendedProperties.UpdatedResourceState)).properties.query)
| where OldLogic != NewLogic

// AzureActivity only give us high level log about rule update and delete. Doesnt have updated details
AzureActivity
| where ActivityStatusValue == 'Success'
|  where (OperationNameValue == "MICROSOFT.SECURITYINSIGHTS/ALERTRULES/WRITE" 
            and parsejson(Properties).statusCode != 'Created' // Ignore Rule creation
        ) 
        or OperationNameValue  == 'MICROSOFT.SECURITYINSIGHTS/ALERTRULES/DELETE'
| project EventSubmissionTimestamp, Caller, CallerIpAddress, OperationNameValue,CorrelationId, RequestBody=parse_json(Properties).requestbody, RespondBody=parse_json(Properties).responseBody,  Level,ActivityStatusValue,ResourceProviderValue, Authorization,Claims,Properties, _ResourceId

// Source: https://github.com/jsa2/kql
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let s = union AADServicePrincipalSignInLogs, AADManagedIdentitySignInLogs
| distinct AppId, ServicePrincipalName;
let massList = s | summarize make_list(AppId);
union AzureDiagnostics, AzureActivity
| extend mass = pack_all(true)
| mv-apply appId = toscalar(massList) to typeof(string) on (where mass contains appId  )
| extend combOp = iff(isempty( OperationNameValue), OperationName, OperationNameValue)
| extend combCategory = iff(isempty( Category), CategoryValue, Category)
| join kind=inner s on $left.appId == $right.AppId
| project ServicePrincipalName,appId, Type, combOp, combCategory, mass

// Source: https://github.com/AnthonyByansi/AZ-104_Microsoft-Azure-Administrator-Associate
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let resourceAccess = azureactivity
    | where Resource == "<resource_id>"  // Replace <resource_id> with your actual resource ID
    | where OperationName == "Access Resource"  // Filter by access operations
    | project TimeGenerated, UserName, ResourceName, AccessType, Details;
resourceAccess
| order by TimeGenerated desc
| limit 50  // Display the latest 50 resource access logs

// Source: https://github.com/sivolko/kql-library
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

let TimeRange = 24h;           // Parameter: Time window
let timeBin = 15m;             // Parameter: Time bucket granularity

// ─────────────────────────────────────────────────────────────────────────────
// QUERY LOGIC — Alert Rule Configuration Changes
// ─────────────────────────────────────────────────────────────────────────────

// Query alert rule configuration changes from Activity Log (via AzureActivity)
// Shows when alert rules were created, updated, or deleted (NOT when alerts fired)
AzureActivity
| where TimeGenerated > ago(TimeRange)
| where CategoryValue == "Administrative"
| where OperationNameValue contains "MICROSOFT.INSIGHTS/SCHEDULEDQUERYRULES"
| extend
    AlertRuleName = tostring(split(ResourceId, "/")[-1]),
    Operation = case(
        OperationNameValue contains "WRITE", "CreateOrUpdate",
        OperationNameValue contains "DELETE", "Delete",
        "Other"
    ),
    ResourceId = column_ifexists("_ResourceId", ResourceId),
    CorrelationId = column_ifexists("CorrelationId", "")
| extend
    TimeBucket = bin(TimeGenerated, timeBin)
| project
    TimeBucket,
    TimeGenerated,
    AlertRuleName,
    Operation,
    ActivityStatusValue,
    ResourceGroup,
    SubscriptionId,
    ResourceId,
    CorrelationId
| order by TimeGenerated desc

// ─────────────────────────────────────────────────────────────────────────────
// EXPECTED RESULTS
// ─────────────────────────────────────────────────────────────────────────────
// Shows when alert rules were created, updated, or deleted.
// Does NOT show when alerts fired.
//
// For alert firing events, use:
// - Azure Resource Graph: az graph query -q "alertsmanagementresources | where type == 'microsoft.alertsmanagement/alerts'"
// - Or configure alert diagnostic settings (Wave 2) to send firing events to AlertEvidence table
//
// For Wave 1 UAT: Verify query syntax runs without error. Results show rule configuration changes only.

// Source: https://github.com/adrianbiro/AzureSentinelMITRE
// Collected: 2026-05-15
// KQL Library - https://github.com/sivolko/kql-library

SigninLogs
| where ResultType !=0
| summarize FailedLoginCount=count() by ResourceDisplayName
| sort by FailedLoginCount desc nulls last

// Azure Portal login errors 
SigninLogs
| where TimeGenerated > ago(30d)
| where AppDisplayName == "Azure Portal"
| extend errorCode_ = tostring(Status.errorCode)
| where errorCode_ != "0"
| extend city_ = tostring(LocationDetails.city), state_ = tostring(LocationDetails.state)
| project UserDisplayName, IPAddress, city_, state_, errorCode_, ResultDescription

// Failed MFA challenge 
// Highlights sign in failures caused by failed MFA challenge. 
SigninLogs
| where ResultType == 50074
| project UserDisplayName, Identity,UserPrincipalName, ResultDescription,  AppDisplayName, AppId, ResourceDisplayName
| summarize FailureCount=count(), FailedResources=dcount(ResourceDisplayName), ResultDescription=any(ResultDescription) by UserDisplayName

// Failed Signin reasons 
// The query list the main reasons for sign in failures. 
SigninLogs
| where ResultType != 0
| summarize Count=count() by ResultDescription, ResultType
| sort by Count desc nulls last

// Failed Linux User Password Change 
// Lists computers wih failed Linux user password change. 
Syslog
| where Facility == 'authpriv' and ((SyslogMessage has 'passwd:chauthtok' and SyslogMessage has 'authentication failure') or SyslogMessage has 'password change failed')
| summarize count() by Computer

// Group Membership changed. 
let group = '<insert your group>';
IdentityDirectoryEvents
| where ActionType == 'Group Membership changed'
| extend AddedToGroup = AdditionalFields['TO.GROUP']
| extend RemovedFromGroup = AdditionalFields['FROM.GROUP']
| extend TargetAccount = AdditionalFields['TARGET_OBJECT.USER']
| where AddedToGroup == group or RemovedFromGroup == group
| project-reorder Timestamp, ActionType, AddedToGroup, RemovedFromGroup, TargetAccount
| limit 100

// High risk users 
// Gets list of the top 100 at high risk users for the last day. 
AADRiskyUsers
| where RiskLastUpdatedDateTime > ago(1d)
| where RiskLevel == "high"
| where RiskState == "atRisk"
| take 100


// LDAP authentication processes with cleartext passwords 
// Find processes that performed LDAP authentication with cleartext passwords. 
IdentityLogonEvents
