//
// Rationale: Attacker-hosted ScreenConnect infrastructure uses custom domains.
// Any ScreenConnect network connection outside *.screenconnect.com warrants
// investigation, particularly to newly registered or unknown domains.
// ============================================================================
DeviceNetworkEvents
| where InitiatingProcessFileName in~ (
    "ScreenConnect.ClientService.exe",
    "ScreenConnect.WindowsClient.exe"
)
| where RemotePort == 443
| where RemoteUrl !endswith ".screenconnect.com"
    and RemoteUrl != ""
