// ============================================================================
let RMMInstallEvents = SecurityEvent
    | where EventID == 7045
    | where ServiceName has "ScreenConnect Client"
    | project RMMInstallTime = TimeGenerated, Computer, RMMService = ServiceName;
let BYOVDDriverLoads = SecurityEvent
    | where EventID == 7045  // Service installed
    | where ImagePath endswith ".sys"
    | where ImagePath !has "Windows\\System32\\drivers\\"
            and ImagePath !has "Windows\\SysWOW64\\drivers\\"
    | project DriverLoadTime = TimeGenerated, Computer, DriverPath = ImagePath,
              DriverService = ServiceName;
RMMInstallEvents
| join kind=inner BYOVDDriverLoads on Computer
| where DriverLoadTime between (RMMInstallTime .. RMMInstallTime + 2h)
| extend TimeDeltaMinutes = datetime_diff('minute', DriverLoadTime, RMMInstallTime)
| project RMMInstallTime, DriverLoadTime, TimeDeltaMinutes, Computer,
          RMMService, DriverPath, DriverService
| order by TimeDeltaMinutes asc

