    TimeGenerated,
    Severity,
    RiskScore,
    User,
    TotalUploadMB,
    FileCount,
    LargestFile_MB,
    UploadRate_MBperMin,
    Files,
    FilePaths,
    IsAfterHours,
    IsPersonalOneDrive,
    HasSensitiveFileTypes,
    UniqueIPs,
    IPList,
