// ---- Block 2: Registry Run / RunOnce key writes ----
let RunKeys =
    DeviceRegistryEvents
    | where Timestamp > ago(7d)
    | where ActionType == "RegistryValueSet"
    | where RegistryKey endswith @'\Software\Microsoft\Windows\CurrentVersion\Run'
         or RegistryKey endswith @'\Software\Microsoft\Windows\CurrentVersion\RunOnce'
         or RegistryKey endswith @'\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Run'
         or RegistryKey endswith @'\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\RunOnce'
    | project Timestamp, DeviceName, Persistence = "RegistryRunKey",
              Artifact = RegistryKey, Details = RegistryValueData,
              InitiatingProcessFileName, InitiatingProcessAccountUpn = tostring(InitiatingProcessAccountUpn);
// ---- Block 3: Files dropped in Startup folders ----
let StartupFolder =
    DeviceFileEvents
    | where Timestamp > ago(7d)
    | where ActionType == "FileCreated"
    | where FolderPath has @"\Start Menu\Programs\Startup"
    | project Timestamp, DeviceName, Persistence = "StartupFolder",
              Artifact = FileName, Details = FolderPath,
              InitiatingProcessFileName, InitiatingProcessAccountUpn;
union ScheduledTasks, RunKeys, StartupFolder
| sort by Timestamp desc

