    | where Timestamp > ago(90d)
    | where RegistryKey has @"\TaskCache\Tasks"
        or RegistryKey has @"\TaskCache\Tree\MicrosoftEdgeUpdateCore"
    | where RegistryValueData has_any (
        "mstelemetry", "WindowsDF", "WindowsUpdateSvc"
    )
        or RegistryKey has "MicrosoftEdgeUpdateCore"
    | project Timestamp, DeviceName,
              AccountName = InitiatingProcessAccountName,
              ActionType,
              FileName = RegistryValueName,
