// ------------------------------------------------------------
// 7. DROPBOX / CATBOX STAGING DOWNLOADS WITH CARRIER EXECUTION
//    FUD payloads stage from Dropbox (primary) with Catbox.moe
//    fallback. These are legitimate services — hunt for
//    downloads that land in a user-writable path and get
//    executed soon after.
// ------------------------------------------------------------
let Stagers =
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where ActionType == "FileCreated"
    | where FileOriginUrl has_any (
        "dropbox.com", "dl.dropboxusercontent.com",
        "catbox.moe", "files.catbox.moe"
    )
    | where FileName endswith ".exe"
        or FileName endswith ".dll"
        or FileName endswith ".zip"
        or FileName endswith ".iso"
        or FileName endswith ".msi"
    | project DeviceId, DeviceName, StageTime = Timestamp,
              StageFile = FileName,
              StagePath = FolderPath, StageUrl = FileOriginUrl,
              StageSHA256 = SHA256;
let Executed =
    DeviceProcessEvents
    | where Timestamp > ago(30d)
    | project DeviceId, ExecTime = Timestamp,
              ExecFile = FileName, ExecPath = FolderPath,
              ExecCmd = ProcessCommandLine,
              ExecSHA256 = SHA256;
Stagers
| join kind=inner Executed on DeviceId
| where datetime_diff('minute', ExecTime, StageTime) between (0 .. 60)
| where ExecPath has StagePath or ExecSHA256 == StageSHA256
| project DeviceName,
          StageTime, StageFile, StagePath, StageUrl,
          ExecTime, ExecFile, ExecPath, ExecCmd
| sort by StageTime desc


// ------------------------------------------------------------
// 8. AZURE TRUSTED SIGNING ABUSE — "Microsoft Identity
//    Verification Root CA" ON NON-SYSTEM BINARIES
//    Legit binaries signed via Azure Trusted Signing exist, but
//    on a typical endpoint the root almost never appears.
//    Hunt for any binary signed by this root that executes
//    from a user-writable path.
// ------------------------------------------------------------
DeviceFileCertificateInfo
| where Timestamp > ago(90d)
| where IsSigned == true
| where Signer has "Microsoft Identity Verification"
    or Issuer has "Microsoft Identity Verification"
| join kind=inner (
    DeviceProcessEvents
    | where Timestamp > ago(90d)
    | where FolderPath has_any (
        @"\AppData\Local\Temp\",
        @"\AppData\Roaming\",
        @"\ProgramData\",
        @"\Users\Public\",
        @"\Downloads\"
    )
    | project DeviceId, ExecTime = Timestamp,
              ExecFile = FileName, ExecPath = FolderPath,
              ExecSHA1 = SHA1, ExecCmd = ProcessCommandLine,
              ExecAccount = AccountName
) on $left.SHA1 == $right.ExecSHA1
| project ExecTime, DeviceName, ExecAccount,
          ExecFile, ExecPath, ExecCmd,
          Signer, Issuer, IsTrusted, IsRootSignerMicrosoft
| sort by ExecTime desc


