    DeviceEvents
    | where Timestamp > ago(30d)
    | where ActionType in~ (
        "AmsiScriptDetection", "AntivirusDetection",
        "TamperingAttempt", "SenseAntiTamperingProtection",
        "AntivirusDefinitionsUpdateFailed"
