// 12. FULL KILL-CHAIN CORRELATION (HIGH FIDELITY)
//     Links the FUD Crypt chain on a single host within 60 min:
//       (a) Staging download from Dropbox / Catbox
//           OR a carrier binary from a user-writable path
//       (b) mpclient.dll loaded from a non-Defender path
//           OR FUD agent / carrier filename observed
//       (c) Outbound to mstelemetrycloud.com / fudcrypt.net
//           OR persistence (WindowsUpdateSvc registry value)
// ------------------------------------------------------------
let Stage1_Delivery =
    union
    (
        DeviceFileEvents
        | where Timestamp > ago(30d)
        | where ActionType == "FileCreated"
        | where FileOriginUrl has_any (
            "dropbox.com", "catbox.moe"
        )
        | where FileName endswith ".exe" or FileName endswith ".dll"
        | project DeviceId, DeviceName,
                  DeliveryTime = Timestamp,
                  DeliveryDetail = strcat(FileName, " <- ", FileOriginUrl)
    ),
    (
        DeviceProcessEvents
        | where Timestamp > ago(30d)
        | where FileName in~ (
            "Zoom.exe", "Slack.exe", "Code.exe",
            "OneDrive.exe", "CCleaner.exe", "ProtonVPN.exe"
        )
        | where FolderPath has_any (
            @"\AppData\Local\Temp\", @"\Downloads\",
            @"\Users\Public\", @"\ProgramData\"
        )
        | where FolderPath !has @"\Program Files"
        | project DeviceId, DeviceName,
                  DeliveryTime = Timestamp,
                  DeliveryDetail = strcat(FileName, " @ ", FolderPath)
    );

let Stage2_Loader =
    union
    (
        DeviceImageLoadEvents
        | where Timestamp > ago(30d)
        | where FileName =~ "mpclient.dll"
        | where FolderPath !has @"\ProgramData\Microsoft\Windows Defender\Platform"
            and FolderPath !has @"\Program Files\Windows Defender\Platform"
        | project DeviceId, LoaderTime = Timestamp,
                  LoaderDetail = strcat("mpclient.dll sideload @ ", FolderPath),
                  LoaderProc = InitiatingProcessFileName
    ),
    (
        DeviceFileEvents
        | where Timestamp > ago(30d)
        | where FileName in~ ("mstelemetry.exe", "WindowsDF.exe")
        | project DeviceId, LoaderTime = Timestamp,
                  LoaderDetail = strcat(FileName, " @ ", FolderPath),
                  LoaderProc = InitiatingProcessFileName
    );

let Stage3_Impact =
    union
    (
        DeviceNetworkEvents
        | where Timestamp > ago(30d)
        | where RemoteUrl has_any (
            "mstelemetrycloud.com", "fudcrypt.net"
        )
        | project DeviceId, ImpactTime = Timestamp,
                  ImpactType = "C2",
                  ImpactDetail = RemoteUrl
    ),
    (
        DeviceRegistryEvents
        | where Timestamp > ago(30d)
        | where RegistryKey has_any (
            @"\CurrentVersion\Run", @"\CurrentVersion\RunOnce"
        )
        | where RegistryValueName in~ ("WindowsUpdateSvc")
            or RegistryValueData has_any (
                "mstelemetry.exe", "WindowsDF.exe"
            )
        | project DeviceId, ImpactTime = Timestamp,
                  ImpactType = "Persistence",
                  ImpactDetail = strcat(RegistryValueName, " = ",
                                        RegistryValueData)
    );

Stage1_Delivery
| join kind=inner Stage2_Loader on DeviceId
| where datetime_diff('minute', LoaderTime, DeliveryTime) between (0 .. 60)
| join kind=inner Stage3_Impact on DeviceId
| where datetime_diff('minute', ImpactTime, LoaderTime) between (0 .. 60)
| project DeviceName,
          DeliveryTime, DeliveryDetail,
          LoaderTime, LoaderProc, LoaderDetail,
          ImpactTime, ImpactType, ImpactDetail
| sort by DeliveryTime desc

