| where SyslogMessage has "syscall=bpf" and SyslogMessage has "a0=0x5"
| extend
    CallerExe   = extract(@'exe="([^"]+)"', 1, SyslogMessage),
    CallerComm  = extract(@' comm="([^"]+)"', 1, SyslogMessage),
    CallerPid   = toint(extract(@' pid=(\d+) ', 1, SyslogMessage)),
