        ProcessName has_any ("mimikatz", "procdump", "dumpert", "nanodump"), "Yes - Known Tool",
        ProcessName has_any ("powershell", "cmd", "wmic"), "Yes - Scripting",
        ProcessName has "task", "Possibly - Task Manager",
        "Unknown"
    ),
    AccessRights = tostring(AccessMask),
    CallingProcess = tostring(ProcessName)
| summarize 
    AccessCount = count(),
    UniqueSources = dcount(ProcessName),
    Processes = make_set(ProcessName),
    Users = make_set(SubjectUserName),
    FirstAccess = min(TimeGenerated),
    LastAccess = max(TimeGenerated)
    by Computer, IsSuspiciousTool, bin(TimeGenerated, 1m)
| where AccessCount > 1 or IsSuspiciousTool startswith "Yes"
| extend 
    Severity = case(
        IsSuspiciousTool == "Yes - Known Tool", "Critical",
        IsSuspiciousTool == "Yes - Scripting", "High",
        AccessCount > 10, "High",
        "Medium"
    ),
    RiskScore = AccessCount * (case(IsSuspiciousTool startswith "Yes", 10, 1))
| project 
    TimeGenerated,
    Severity,
    Computer,
    IsSuspiciousTool,
    AccessCount,
    UniqueSources,
    Processes,
    Users,
    RiskScore,
    FirstAccess,
    LastAccess
| order by Severity desc, RiskScore desc

