// 9. NTDS.DIT EXFILTRATION — AD DATABASE THEFT
//    With SYSTEM on a DC, attackers steal the AD database
//    (ntds.dit) via ntdsutil, vssadmin, or direct copy.
//    Full domain credential compromise.
// ------------------------------------------------------------
union
(
    DeviceProcessEvents
    | where Timestamp > ago(30d)
    | where ProcessCommandLine has_any (
        "ntdsutil", "ntds.dit",
        "vssadmin create shadow",
        "esentutl", "IFM",
        "activate instance ntds",
        @"copy \\?\GLOBALROOT\Device\HarddiskVolumeShadowCopy"
    )
    | project Timestamp, DeviceName, AccountName,
              FileName, ProcessCommandLine,
              InitiatingProcessFileName, Source = "Process"
),
(
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where FileName =~ "ntds.dit"
    | where ActionType in ("FileCopied", "FileCreated", "FileRenamed")
    | where FolderPath !has @"\Windows\NTDS"
    | project Timestamp, DeviceName, AccountName = "",
              FileName, ProcessCommandLine = FolderPath,
              InitiatingProcessFileName, Source = "FileCopy"
)
| sort by Timestamp desc


// ------------------------------------------------------------
// 10. DCSYNC ATTACK — DIRECTORY REPLICATION FROM NON-DC HOST
//     Post-exploitation attackers use DCSync (mimikatz) to
//     replicate credentials remotely. Hunt for replication
//     requests from non-DC sources.
// ------------------------------------------------------------
IdentityQueryEvents
| where Timestamp > ago(14d)
| where ActionType == "SAMR query"
    or QueryType has_any ("GetNCChanges", "DRSGetNCChanges",
                           "Replication")
| where DeviceName !has_any ("DC", "dc")   // adjust to your DC naming
| project Timestamp, DeviceName, AccountUpn,
          ActionType, QueryType, QueryTarget
| sort by Timestamp desc


// ------------------------------------------------------------
// 11. AUDIT LOG CLEARED ON DOMAIN CONTROLLERS
//     Post-exploitation cleanup: attackers clear Security,
//     System, or Application event logs to cover tracks.
//     Event ID 1102 (Security log cleared) on a DC is always
//     worth investigating.
// ------------------------------------------------------------
DeviceEvents
| where Timestamp > ago(30d)
| where ActionType has_any ("SecurityLogCleared", "AuditLogCleared",
                             "EventLogCleared")
| project Timestamp, DeviceName, ActionType, AccountName,
          InitiatingProcessFileName, InitiatingProcessCommandLine,
          AdditionalFields
| sort by Timestamp desc


// ------------------------------------------------------------
// 12. FULL KILL-CHAIN CORRELATION (HIGH FIDELITY)
//     Links the AD RCE exploitation chain on a single DC
//     within 2 hours:
//       (a) High-volume RPC connections (port 135 + dynamic)
//       (b) Unexpected child process from lsass/ntdsa
//       (c) Credential access or AD database theft
//     Three-stage correlation — very low false positive rate.
// ------------------------------------------------------------
let Stage1_RPC =
    DeviceNetworkEvents
    | where Timestamp > ago(14d)
    | where RemotePort in (135, 593)
        or RemotePort between (49152 .. 65535)
    | where InitiatingProcessFileName !in~ (
        "svchost.exe", "lsass.exe", "dns.exe",
        "MsMpEng.exe", "MsSense.exe"
    )
    | summarize RPCBurst = count(),
                DistinctPorts = dcount(RemotePort)
            by DeviceName, RemoteIP, bin(Timestamp, 10m)
    | where RPCBurst > 50 and DistinctPorts > 5
    | project DeviceName, SourceDevice = DeviceName,
              DCIP = RemoteIP, RPCTime = Timestamp, RPCBurst;

let Stage2_Exec =
    DeviceProcessEvents
    | where Timestamp > ago(14d)
    | where InitiatingProcessFileName in~ (
        "lsass.exe", "ntdsa.exe",
        "Microsoft.ActiveDirectory.WebServices.exe"
    )
    | where FileName in~ (
        "cmd.exe", "powershell.exe", "pwsh.exe",
        "rundll32.exe", "net.exe", "whoami.exe",
        "certutil.exe", "bitsadmin.exe", "wmic.exe",
        "nltest.exe"
    )
    | project DeviceName, ExecTime = Timestamp,
              ParentProcess = InitiatingProcessFileName,
              ChildProcess = FileName,
              ExecCmd = ProcessCommandLine;

let Stage3_CredTheft =
    DeviceProcessEvents
    | where Timestamp > ago(14d)
    | where ProcessCommandLine has_any (
        "sekurlsa", "logonpasswords", "dcsync",
        "lsadump", "ntds.dit", "ntdsutil",
        "MiniDump", "comsvcs",
        "vssadmin create shadow",
        "procdump -ma lsass"
    )
    | project DeviceName, TheftTime = Timestamp,
              TheftTool = FileName,
              TheftCmd = ProcessCommandLine;

Stage2_Exec
| join kind=leftouter Stage1_RPC on DeviceName
| where datetime_diff('minute', ExecTime, RPCTime) between (-10 .. 120)
    or isempty(RPCTime)
| join kind=leftouter Stage3_CredTheft on DeviceName
| where datetime_diff('minute', TheftTime, ExecTime) between (0 .. 120)
    or isempty(TheftTime)
| project DeviceName, RPCTime, RPCBurst,
          ExecTime, ParentProcess, ChildProcess, ExecCmd,
          TheftTime, TheftTool, TheftCmd
| sort by ExecTime desc

